/**
 * Segment Tree implementation for Range Maximum Query and Point Update (Max).
 * This is used to maintain the maximum DP scores associated with specific values of nums[j].
 */
class SegmentTree {
    /**
     * @param {number} size The maximum value index (V_max).
     */
    constructor(size) {
        // Size of the array is 1-based up to size. Tree needs ~4*size nodes.
        this.size = size;
        this.tree = new Array(4 * size + 1).fill(0);
    }

    /**
     * Updates the value at a specific index (value) to be the maximum of its current value and new_val.
     * @param {number} value The index (value of nums[j]) to update (1-based).
     * @param {number} new_val The new maximum score to potentially store.
     */
    update(value, new_val) {
        this._updateRecursive(1, 1, this.size, value, new_val);
    }

    _updateRecursive(node, start, end, idx, val) {
        if (start === end) {
            // Leaf node: Update only if new_val is greater
            this.tree[node] = Math.max(this.tree[node], val);
            return;
        }

        const mid = Math.floor((start + end) / 2);
        if (idx <= mid) {
            this._updateRecursive(2 * node, start, mid, idx, val);
        } else {
            this._updateRecursive(2 * node + 1, mid + 1, end, idx, val);
        }

        // Internal node update: store the maximum of children
        this.tree[node] = Math.max(this.tree[2 * node], this.tree[2 * node + 1]);
    }

    /**
     * Queries the maximum value in the range [L, R] (1-based indices).
     * @param {number} L Start of the range (inclusive).
     * @param {number} R End of the range (inclusive).
     * @returns {number} The maximum value in the range, or 0 if the range is invalid/empty.
     */
    query(L, R) {
        if (L > R || L > this.size || R < 1) {
            return 0;
        }
        L = Math.max(1, L);
        R = Math.min(this.size, R);
        return this._queryRecursive(1, 1, this.size, L, R);
    }

    _queryRecursive(node, start, end, L, R) {
        // Current segment is outside the query range
        if (start > R || end < L) {
            return 0;
        }

        // Current segment is completely inside the query range
        if (L <= start && end <= R) {
            return this.tree[node];
        }

        // Partial overlap
        const mid = Math.floor((start + end) / 2);
        const p1 = this._queryRecursive(2 * node, start, mid, L, R);
        const p2 = this._queryRecursive(2 * node + 1, mid + 1, end, L, R);

        return Math.max(p1, p2);
    }
}


/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const N = nums.length;
    if (N === 0) return 0;

    // Constraints guarantee 1 <= nums[i] <= 10^5
    const V_MAX = 100000;

    // DP_UP[i]: Max score ending at i, where nums[i] > nums[i_{m-1}] (ends going up: ... < nums[i])
    // DP_DOWN[i]: Max score ending at i, where nums[i] < nums[i_{m-1}] (ends going down: ... > nums[i])
    const DP_UP = new Array(N).fill(0);
    const DP_DOWN = new Array(N).fill(0);

    // BIT_UP stores max DP_UP[j] achieved at value nums[j]
    // BIT_DOWN stores max DP_DOWN[j] achieved at value nums[j]
    const BIT_UP = new SegmentTree(V_MAX);
    const BIT_DOWN = new SegmentTree(V_MAX);

    let max_score = 0;

    for (let i = 0; i < N; i++) {
        const current_val = nums[i];

        // 1. Calculate DP_UP[i]: Sequence ends ... < current_val. Must come from DP_DOWN[j] where nums[j] < current_val.
        // Query BIT_DOWN for max score where value v < current_val (i.e., range [1, current_val - 1])
        const max_prev_down = BIT_DOWN.query(1, current_val - 1);
        // Base case: Length 1 subsequence (score current_val) is always possible, handled by max(0, ...)
        DP_UP[i] = current_val + Math.max(0, max_prev_down);

        // 2. Calculate DP_DOWN[i]: Sequence ends ... > current_val. Must come from DP_UP[j] where nums[j] > current_val.
        // Query BIT_UP for max score where value v > current_val (i.e., range [current_val + 1, V_MAX])
        const max_prev_up = BIT_UP.query(current_val + 1, V_MAX);
        // Base case: Length 1 subsequence
        DP_DOWN[i] = current_val + Math.max(0, max_prev_up);

        // Update overall maximum score
        max_score = Math.max(max_score, DP_UP[i], DP_DOWN[i]);

        // 3. Update the BITs for future indices (j = i + k, i + k + 1, ...)
        // Index i becomes available as a predecessor for i' >= i + k.
        // We update the BITs now, as they will be used when calculating DP for i' >= i + k.
        BIT_UP.update(current_val, DP_UP[i]);
        BIT_DOWN.update(current_val, DP_DOWN[i]);
    }

    return max_score;
}

